using System.ComponentModel;
using System.Net;
using System.Text;
using System.Text.RegularExpressions;
using Microsoft.Extensions.AI;
using OpenAI;

// ── Configuration ──
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

// ── Build chat client with automatic tool invocation ──
IChatClient client = new ChatClientBuilder(
        new OpenAIClient(apiKey).GetChatClient(modelId).AsIChatClient())
    .UseFunctionInvocation()
    .Build();

// ── Tools ──
var notebook = new Notebook();

var tools = new List<AITool>
{
    AIFunctionFactory.Create(SearchWeb),
    AIFunctionFactory.Create(notebook.AddNote),
    AIFunctionFactory.Create(notebook.GetNotes),
};

// ── System prompt ──
var systemPrompt = """
    You are a research agent. Your job is to research a topic thoroughly using the
    available tools, then produce a well-structured summary.

    Workflow:
    1. Break the topic into sub-questions.
    2. Use the SearchWeb tool to find information for each sub-question.
    3. Use AddNote to save important facts, data points, and source URLs.
    4. After gathering enough information, use GetNotes to review your collected notes.
    5. Produce a final, well-organized summary with sections and references.

    Be thorough: perform multiple searches to cover different angles of the topic.
    """;

// ── Get the research topic ──
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrEmpty(topic))
{
    Console.Error.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\n🔍 Researching: {topic}\n");

// ── Run the agent ──
var messages = new List<ChatMessage>
{
    new(ChatRole.System, systemPrompt),
    new(ChatRole.User,
        $"Research the following topic and provide a comprehensive summary:\n\n{topic}"),
};

var response = await client.GetResponseAsync(messages, new ChatOptions { Tools = tools });

Console.WriteLine();
Console.WriteLine("═══════════════════════════════════════════");
Console.WriteLine("  RESEARCH SUMMARY");
Console.WriteLine("═══════════════════════════════════════════");
Console.WriteLine(response.Text);
Console.WriteLine("═══════════════════════════════════════════");

// ═══════════════════════════════════════════════════════════════════
//  Tools
// ═══════════════════════════════════════════════════════════════════

// ── Web search via DuckDuckGo HTML ──
[Description("Search the web for information. Returns relevant snippets from search results.")]
static async Task<string> SearchWeb(
    [Description("The search query")] string query)
{
    using var http = new HttpClient();
    http.DefaultRequestHeaders.UserAgent.ParseAdd(
        "Mozilla/5.0 (compatible; ResearchAgent/1.0)");
    http.Timeout = TimeSpan.FromSeconds(15);

    var url = $"https://html.duckduckgo.com/html/?q={Uri.EscapeDataString(query)}";

    try
    {
        Console.WriteLine($"  🌐 Searching: {query}");
        var html = await http.GetStringAsync(url);
        var results = ParseSearchResults(html);

        if (results.Count == 0)
            return "No search results found.";

        var sb = new StringBuilder();
        foreach (var (i, r) in results.Take(5).Select((r, i) => (i, r)))
        {
            sb.AppendLine($"[{i + 1}] {r.Title}");
            sb.AppendLine($"    {r.Snippet}");
            sb.AppendLine($"    URL: {r.Url}");
            sb.AppendLine();
        }

        return sb.ToString();
    }
    catch (Exception ex)
    {
        return $"Search failed: {ex.Message}";
    }
}

static List<SearchResult> ParseSearchResults(string html)
{
    var results = new List<SearchResult>();

    var pattern = new Regex(
        @"<a[^>]+class=""result__a""[^>]*href=""([^""]*)""[^>]*>(.*?)</a>" +
        @".*?<a[^>]+class=""result__snippet""[^>]*>(.*?)</a>",
        RegexOptions.Singleline);

    foreach (Match match in pattern.Matches(html))
    {
        var rawUrl = WebUtility.HtmlDecode(match.Groups[1].Value.Trim());
        var title = StripHtml(match.Groups[2].Value);
        var snippet = StripHtml(match.Groups[3].Value);

        // Unwrap DuckDuckGo redirect URLs
        if (rawUrl.Contains("uddg="))
        {
            var uddg = Regex.Match(rawUrl, @"uddg=([^&]+)");
            if (uddg.Success)
                rawUrl = Uri.UnescapeDataString(uddg.Groups[1].Value);
        }

        if (!string.IsNullOrWhiteSpace(title))
            results.Add(new SearchResult(title, snippet, rawUrl));
    }

    return results;
}

static string StripHtml(string html)
{
    var text = Regex.Replace(html, @"<[^>]+>", "");
    return WebUtility.HtmlDecode(text).Trim();
}

record SearchResult(string Title, string Snippet, string Url);

