class Notebook
{
    private readonly List<string> _notes = [];

    [Description(
        "Save a note to the research notebook. Use this to record important " +
        "facts, data points, or source URLs discovered during research.")]
    public string AddNote(
        [Description("The note content to save")] string note)
    {
        _notes.Add(note);
        Console.WriteLine($"  📝 Note saved ({_notes.Count} total)");
        return $"Note saved. You now have {_notes.Count} note(s).";
    }

    [Description("Retrieve all saved notes from the research notebook.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        var sb = new StringBuilder();
        for (var i = 0; i < _notes.Count; i++)
            sb.AppendLine($"Note {i + 1}: {_notes[i]}");

        return sb.ToString();
    }
}

